import os, base64, gzip
base = os.path.dirname(os.path.abspath(__file__))
FILES = [
  ('src\\\\app\\\\api\\\\pix\\\\route.ts', ''),
  ('src\\\\app\\\\checkout\\\\page.tsx', ''),
]
ok = 0
for rel, data in FILES:
    try:
        dest = os.path.join(base, rel)
        os.makedirs(os.path.dirname(dest), exist_ok=True)
        with open(dest, "w", encoding="utf-8", newline="\n") as f:
            f.write(gzip.decompress(base64.b64decode(data)).decode("utf-8"))
        print("OK:", rel)
        ok += 1
    except Exception as e:
        print("ERRO:", rel, e)

# Instala biblioteca qrcode
import subprocess
print("Instalando qrcode...")
subprocess.run(["npm", "install", "qrcode", "@types/qrcode"], cwd=base, shell=True)

# Fix path da API PIX
import re
pix_fp = os.path.join(base, "src", "app", "api", "pix", "route.ts")
with open(pix_fp, "r", encoding="utf-8") as f:
    c = f.read()
c = re.sub(r"from '[./]+lib/supabase-server'", "from '../../../lib/supabase-server'", c)
with open(pix_fp, "w", encoding="utf-8", newline="\n") as f:
    f.write(c)
print("OK: path PIX corrigido")

print(f"\nTotal: {ok}/2 arquivos instalados")
print("PIX direto com QR Code instalado!")
print("Rode: npm run build")